{
  "family": "Ritter Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC(C)(C)O",
      "CC#N"
    ],
    "product_smiles": [
      "CC(=O)NC(C)(C)C"
    ],
    "optional_reagent_smiles": [
      "O=S(=O)(O)O"
    ],
    "rationale": "This is the classic textbook example of the Ritter reaction, demonstrating the formation of a stable tert-butyl carbocation from tert-butanol under strong acid (sulfuric acid), which is then trapped by acetonitrile. Subsequent hydrolysis of the resulting nitrilium ion intermediate yields N-tert-butylacetamide. All reactants and products are simple, acyclic, and lack complex functional groups, making it a clear and unambiguous representation of the core transformation.",
    "collision_avoidance_note": "This example uses simple, acyclic aliphatic substrates (tert-butanol and acetonitrile) to avoid overlap with reactions involving aromatic rings (e.g., Friedel-Crafts), rearrangements (e.g., Pinacol, Wagner-Meerwein), or other complex carbocation pathways. The choice of a tertiary alcohol as the carbocation precursor is specific and characteristic of the Ritter reaction, distinguishing it from reactions that might involve nitriles but different initiation steps."
  }
}
